'use client';

import React, { useEffect, useState } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import { toast } from 'sonner';
import axios from 'axios';
import { Star, Check, X, PauseCircle } from 'lucide-react';

interface Review {
  _id: string;
  user: { name: string; email: string };
  plant: { name: string };
  rating: number;
  comment: string;
  status: 'pending' | 'accepted' | 'frozen';
  date: string;
}

export default function ReviewsPage() {
  const [reviews, setReviews] = useState<Review[]>([]);

  useEffect(() => {
    // 🚀 Fetch pending reviews from API
    // axios.get('/api/reviews/pending', { withCredentials: true })
    //   .then(res => setReviews(res.data))
    //   .catch(err => console.error(err));

    // Dummy data for testing
    setReviews([
      {
        _id: 'r1',
        user: { name: 'Priya Sharma', email: 'priya@example.com' },
        plant: { name: 'Monstera Deliciosa' },
        rating: 5,
        comment: 'Beautiful plant, arrived healthy!',
        status: 'pending',
        date: '2025-11-09',
      },
      {
        _id: 'r2',
        user: { name: 'Amit Verma', email: 'amit@example.com' },
        plant: { name: 'Snake Plant' },
        rating: 4,
        comment: 'Good quality but delayed delivery.',
        status: 'pending',
        date: '2025-11-08',
      },
    ]);
  }, []);

  const handleAccept = async (id: string) => {
    try {
      // await axios.post(`/api/reviews/accept/${id}`, {}, { withCredentials: true });
      setReviews((prev) => prev.filter((r) => r._id !== id));
      toast.success('✅ Review accepted & published');
    } catch (err) {
      console.error(err);
      toast.error('Failed to accept review');
    }
  };

  const handleReject = async (id: string) => {
    try {
      // await axios.delete(`/api/reviews/${id}`, { withCredentials: true });
      setReviews((prev) => prev.filter((r) => r._id !== id));
      toast.success('❌ Review rejected & deleted');
    } catch (err) {
      console.error(err);
      toast.error('Failed to reject review');
    }
  };

  const handleFreeze = async (id: string) => {
    try {
      // await axios.post(`/api/reviews/freeze/${id}`, {}, { withCredentials: true });
      setReviews((prev) =>
        prev.map((r) => (r._id === id ? { ...r, status: 'frozen' } : r))
      );
      toast.info('🧊 Review frozen (hidden from client)');
    } catch (err) {
      console.error(err);
      toast.error('Failed to freeze review');
    }
  };

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-2xl font-bold">User Reviews</h1>

      <Card>
        <CardHeader>
          <CardTitle>Pending Reviews</CardTitle>
        </CardHeader>
        <CardContent>
          <ScrollArea className="max-h-[500px]">
            <table className="w-full text-sm md:text-base">
              <thead>
                <tr className="text-left border-b">
                  <th className="py-2">User</th>
                  <th className="py-2">Plant</th>
                  <th className="py-2">Rating</th>
                  <th className="py-2">Comment</th>
                  <th className="py-2">Date</th>
                  <th className="py-2 text-center">Actions</th>
                </tr>
              </thead>
              <tbody>
                {reviews.length === 0 ? (
                  <tr>
                    <td colSpan={6} className="text-center py-4 text-gray-500">
                      No reviews available
                    </td>
                  </tr>
                ) : (
                  reviews.map((review) => (
                    <tr key={review._id} className="border-t">
                      <td className="py-2">
                        <div className="font-medium">{review.user.name}</div>
                        <div className="text-xs text-gray-500">
                          {review.user.email}
                        </div>
                      </td>
                      <td className="py-2">{review.plant.name}</td>
                      <td className="py-2">
                        <div className="flex items-center gap-1 text-yellow-500">
                          {Array.from({ length: review.rating }).map((_, i) => (
                            <Star key={i} size={14} fill="currentColor" />
                          ))}
                        </div>
                      </td>
                      <td className="py-2 max-w-[250px] truncate">
                        {review.comment}
                      </td>
                      <td className="py-2">{review.date}</td>
                      <td className="py-2 flex justify-center gap-2">
                        <Button
                          size="sm"
                          variant="default"
                          onClick={() => handleAccept(review._id)}
                        >
                          <Check size={14} className="mr-1" /> Accept
                        </Button>
                        <Button
                          size="sm"
                          variant="destructive"
                          onClick={() => handleReject(review._id)}
                        >
                          <X size={14} className="mr-1" /> Reject
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => handleFreeze(review._id)}
                        >
                          <PauseCircle size={14} className="mr-1" /> Freeze
                        </Button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </ScrollArea>
        </CardContent>
      </Card>
    </div>
  );
}
